const recentFiles = ($('Drive: Geändert letzte 24h').first().json.files || []);
const keyDocs = ($('Drive: Key Docs (7 Tage)').first().json.files || []);

const today = new Date().toISOString().slice(0, 10);

// MIME type mapping
const TYPES = {
  'application/vnd.google-apps.document': 'Doc',
  'application/vnd.google-apps.spreadsheet': 'Sheet',
  'application/vnd.google-apps.presentation': 'Slides',
  'application/vnd.google-apps.form': 'Form',
  'application/pdf': 'PDF'
};

// Zähle nach Typ
const typeCounts = {};
recentFiles.forEach(f => {
  const t = TYPES[f.mimeType] || 'Andere';
  typeCounts[t] = (typeCounts[t] || 0) + 1;
});

const typeStr = Object.entries(typeCounts)
  .sort((a, b) => b[1] - a[1])
  .map(([t, c]) => `${c}x ${t}`)
  .join(', ');

// Wer hat bearbeitet?
const editors = {};
recentFiles.forEach(f => {
  const name = f.lastModifyingUser?.displayName || 'Unbekannt';
  editors[name] = (editors[name] || 0) + 1;
});
const editorStr = Object.entries(editors)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 4)
  .map(([n, c]) => `${n}: ${c}`)
  .join(', ');

// Key Docs Highlights
const keyDocNames = keyDocs
  .slice(0, 5)
  .map(f => f.name)
  .join(', ');

let parts = [];
parts.push(`${recentFiles.length} Dateien geändert (24h)`);
if (typeStr) parts.push(`Typen: ${typeStr}`);
if (editorStr) parts.push(`Bearbeitet von: ${editorStr}`);
if (keyDocNames) parts.push(`Key Docs (7d): ${keyDocNames}`);

const zusammenfassung = parts.join('. ') + '.';

return [{
  json: {
    id: 'kf-gdrive-' + today,
    pid: null,
    quelle: 'gdrive',
    typ: 'aktivitaet',
    zusammenfassung,
    rohdaten: {
      recentCount: recentFiles.length,
      typeCounts,
      editors,
      keyDocs: keyDocs.slice(0, 5).map(f => ({ name: f.name, url: f.webViewLink, modified: f.modifiedTime }))
    },
    relevanz: 'niedrig',
    created_at: new Date().toISOString(),
    gueltig_bis: today
  }
}];
